#include<stdio.h>

int main(){
	int y, jwi1, jwi2, jwi3, jwi4;
	scanf("%d", &y);

	while(1){
		y += 1;
		jwi1 = y % 10;
		jwi2 = (y/10)% 10;
		jwi3 = ((y/10)/10)% 10;
		jwi4 = (((y/10)/10)/10)% 10;
		if(jwi1 != jwi2 && jwi1 != jwi3 && jwi1 != jwi4 &&
		   jwi2 != jwi3 && jwi2 != jwi4 && jwi3 != jwi4) break;
	}
	printf("%d", y);
	return 0;
}

